import { ref, computed } from 'vue';
import WorkExperienceContent from './WorkExperienceContent.vue';
import EducationContent from './EducationContent.vue';
import ProjectContent from './ProjectContent.vue';
import SkillContent from './SkillContent.vue';
import PortfolioContent from './PortfolioContent.vue';
import SocialLinkContent from './SocialLinkContent.vue';
import LanguageContent from './LanguageContent.vue';
import { ElMessage } from 'element-plus';
import profile from '@/api/profile';
export default {
  __name: 'ModuleList',
  props: {
    moduleData: {
      type: Object,
      required: true
    }
  },
  emits: ['update:moduleData'],
  setup(__props, {
    expose: __expose,
    emit: __emit
  }) {
    __expose();
    const props = __props;
    const emit = __emit;

    // 获取对应的内容组件
    const getComponentByType = type => {
      const componentMap = {
        work_experience: WorkExperienceContent,
        education: EducationContent,
        project: ProjectContent,
        skill: SkillContent,
        portfolio: PortfolioContent,
        social_link: SocialLinkContent,
        language: LanguageContent
      };
      return componentMap[type];
    };

    // 模块配置
    const modules = [{
      type: 'work_experience',
      title: '工作经历',
      canAdd: true
    }, {
      type: 'education',
      title: '教育经历',
      canAdd: true
    }, {
      type: 'project',
      title: '项目经历',
      canAdd: true
    }, {
      type: 'skill',
      title: '技能特长',
      canAdd: true
    }, {
      type: 'portfolio',
      title: '作品展示',
      canAdd: true
    }, {
      type: 'social_link',
      title: '社交主页',
      canAdd: true
    }, {
      type: 'language',
      title: '语言能力',
      canAdd: true
    }];

    // 处理添加操作
    const handleAdd = type => {
      emit('add', type);
    };

    // 处理编辑操作
    const handleEdit = (type, item) => {
      emit('edit', type, item);
    };

    // 处理删除操作
    const handleDelete = async (type, id) => {
      try {
        await profile.deleteModuleItem(type, id);
        ElMessage.success('删除成功');
        // 通知父组件刷新数据
        emit('delete', type, id);
      } catch (error) {
        console.error('删除失败:', error);
        ElMessage.error(error.message || '删除失败');
      }
    };
    const __returned__ = {
      props,
      emit,
      getComponentByType,
      modules,
      handleAdd,
      handleEdit,
      handleDelete,
      ref,
      computed,
      WorkExperienceContent,
      EducationContent,
      ProjectContent,
      SkillContent,
      PortfolioContent,
      SocialLinkContent,
      LanguageContent,
      get ElMessage() {
        return ElMessage;
      },
      get profile() {
        return profile;
      }
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
